        add("bestiary.confluence.filter.surface.title", "Surface");
        add("bestiary.confluence.filter.surface.desc", "The Surface layer is located between y40 ~ y260.");
        add("bestiary.confluence.filter.underground.title", "Underground");
        add("bestiary.confluence.filter.underground.desc", "The Underground layer is located between y0 ~ y40.");
        add("bestiary.confluence.filter.cave.title", "Cave");
        add("bestiary.confluence.filter.cave.desc", "The Cavern layer is located between y-64 ~ y0.");
        add("bestiary.confluence.filter.desert.title", "Desert");
        add("bestiary.confluence.filter.desert.desc", "The Desert is a biome primarily composed of sand blocks and cacti.");
        add("bestiary.confluence.filter.underground_desert.title", "Underground Desert");
        add("bestiary.confluence.filter.underground_desert.desc", "The Underground Desert is a biome located directly beneath the world's main Desert.");
        add("bestiary.confluence.filter.snow.title", "Snow");
        add("bestiary.confluence.filter.snow.desc", "The Snow biome is a polar-themed surface biome.");
        add("bestiary.confluence.filter.underground_snow.title", "Underground Snow");
        add("bestiary.confluence.filter.underground_snow.desc", "The Underground Snow is a biome and is the underground variant of the Snow biome.");
        add("bestiary.confluence.filter.the_corruption.title", "The Corruption");
        add("bestiary.confluence.filter.the_corruption.desc", "The Corruption is an evil biome with a theme of deep purple wasteland, death, and decay.");
        add("bestiary.confluence.filter.underground_corruption.title", "Underground Corruption");
        add("bestiary.confluence.filter.underground_corruption.desc", "The Underground Corruption is a biome. It is the underground version of the surface Corruption, appearing from the Cavern layer and below.");
        add("bestiary.confluence.filter.corrupt_desert.title", "Corrupt Desert");
        add("bestiary.confluence.filter.corrupt_desert.desc", "The Corruption can spread through Deserts, transforming them into Corrupt Deserts.");
        add("bestiary.confluence.filter.corrupt_cave_desert.title", "Corrupt Cave Desert");
        add("bestiary.confluence.filter.corrupt_cave_desert.desc", "The Corruption can spread through the Underground Desert, transforming it into a Corrupt Cave Desert.");
        add("bestiary.confluence.filter.corrupt_ice.title", "Corrupt Ice");
        add("bestiary.confluence.filter.corrupt_ice.desc", "The Corruption can spread through the Underground Snow, transforming it into Corrupt Ice.");
        add("bestiary.confluence.filter.the_crimson.title", "The Crimson");
        add("bestiary.confluence.filter.the_crimson.desc", "The Crimson is an evil biome with a theme of fleshy infection and blood.");
        add("bestiary.confluence.filter.underground_crimson.title", "Underground Crimson");
        add("bestiary.confluence.filter.underground_crimson.desc", "The Underground Crimson is a biome. It is the underground version of the surface Crimson, appearing from the Cavern layer and below.");
        add("bestiary.confluence.filter.crimson_desert.title", "Crimson Desert");
        add("bestiary.confluence.filter.crimson_desert.desc", "The Crimson can spread through Deserts, transforming them into Crimson Deserts.");
        add("bestiary.confluence.filter.crimson_cave_desert.title", "Crimson Cave Desert");
        add("bestiary.confluence.filter.crimson_cave_desert.desc", "The Crimson can spread through the Underground Desert, transforming it into a Crimson Cave Desert.");
        add("bestiary.confluence.filter.crimson_ice.title", "Crimson Ice");
        add("bestiary.confluence.filter.crimson_ice.desc", "The Crimson can spread through the Underground Snow, transforming it into Crimson Ice.");
        add("bestiary.confluence.filter.the_hallow.title", "The Hallow");
        add("bestiary.confluence.filter.the_hallow.desc", "The Hallow is a Hardmode surface biome characterized by its bright, fairy-tale imagery.");
        add("bestiary.confluence.filter.underground_hallow.title", "Underground Hallow");
        add("bestiary.confluence.filter.underground_hallow.desc", "The Underground Hallow is the underground version of the surface Hallow, appearing from the Cavern layer and below.");
        add("bestiary.confluence.filter.hallow_desert.title", "Hallow Desert");
        add("bestiary.confluence.filter.hallow_desert.desc", "The Hallow can spread through Deserts, transforming them into Hallow Deserts.");
        add("bestiary.confluence.filter.hallow_cave_desert.title", "Hallow Cave Desert");
        add("bestiary.confluence.filter.hallow_cave_desert.desc", "The Hallow can spread through the Underground Desert, transforming it into a Hallow Cave Desert.");
        add("bestiary.confluence.filter.hallow_ice.title", "Hallow Ice");
        add("bestiary.confluence.filter.hallow_ice.desc", "The Hallow can spread through the Underground Snow, transforming it into Hallow Ice.");
        add("bestiary.confluence.filter.the_jungle.title", "The Jungle");
        add("bestiary.confluence.filter.the_jungle.desc", "The Jungle is a surface biome primarily composed of grass, vines, mud, jungle trees, bamboo, and water pools.");
        add("bestiary.confluence.filter.underground_jungle.title", "Underground Jungle");
        add("bestiary.confluence.filter.underground_jungle.desc", "The Underground Jungle is a dense network of small caves, primarily composed of mud, water pools, spiky bushes, and hive traps. It lies beneath the surface Jungle biome and extends into the Cavern layer.");
        add("bestiary.confluence.filter.surface_mushroom.title", "Surface Mushroom");
        add("bestiary.confluence.filter.surface_mushroom.desc", "The Glowing Mushroom biome, also known as the Glowing Mushroom Fields, is a biome characterized by Mushroom Grass, Glowing Mushrooms, and giant Glowing Mushrooms that grow on mud blocks.");
        add("bestiary.confluence.filter.underground_mushroom.title", "Underground Mushroom");
        add("bestiary.confluence.filter.underground_mushroom.desc", "The Glowing Mushroom biome, also known as the Glowing Mushroom Fields, is a biome characterized by Mushroom Grass, Glowing Mushrooms, and giant Glowing Mushrooms that grow on mud blocks.");
        add("bestiary.confluence.filter.sky.title", "Sky");
        add("bestiary.confluence.filter.sky.desc", "The upper Sky is the layer that forms the top of the world.");
        add("bestiary.confluence.filter.ocean.title", "Ocean");
        add("bestiary.confluence.filter.ocean.desc", "The Ocean is a biome primarily composed of water and sand.");
        add("bestiary.confluence.filter.marble.title", "Marble");
        add("bestiary.confluence.filter.marble.desc", "The Marble Cave is a mini-biome that appears in the Cavern layer.");
        add("bestiary.confluence.filter.granite.title", "Granite");
        add("bestiary.confluence.filter.granite.desc", "The Granite Cave is a mini-biome that appears in the Underground or Cavern layer.");
        add("bestiary.confluence.filter.the_temple.title", "The Temple");
        add("bestiary.confluence.filter.the_temple.desc", "The Jungle Temple (also known as the Jungle Lizard Temple) is a closed structure located in the Underground Jungle, built from Jungle Lizard Bricks.");
        add("bestiary.confluence.filter.the_dungeon.title", "The Dungeon");
        add("bestiary.confluence.filter.the_dungeon.desc", "The Dungeon is a massive underground brick maze.");
        add("bestiary.confluence.filter.the_nether.title", "The Nether");
        add("bestiary.confluence.filter.the_nether.desc", "The Nether is the deepest layer in the world. It merges with the Underworld to form the Ash biome.");
        add("bestiary.confluence.filter.spider_nest.title", "Spider Nest");
        add("bestiary.confluence.filter.spider_nest.desc", "The Spider Nest, also known as the Spider Cave or Spider Den, is a mini-biome located in the Cavern layer.");
        add("bestiary.confluence.filter.graveyard.title", "Graveyard");
        add("bestiary.confluence.filter.graveyard.desc", "The Graveyard is a mini-biome that forms when there are five or more Tombstones near the player.");
        add("bestiary.confluence.filter.daytime.title", "Daytime");
        add("bestiary.confluence.filter.daytime.desc", "From 4:30 to 19:30.");
        add("bestiary.confluence.filter.nighttime.title", "Nighttime");
        add("bestiary.confluence.filter.nighttime.desc", "From 19:30 to 4:30.");
        add("bestiary.confluence.filter.blood_moon.title", "Blood Moon");
        add("bestiary.confluence.filter.blood_moon.desc", "The Blood Moon is an event that occurs during the entire night and only affects the Surface layer.");
        add("bestiary.confluence.filter.eclipse.title", "Eclipse");
        add("bestiary.confluence.filter.eclipse.desc", "The Eclipse is a Hardmode event that can occasionally occur after at least one Mechanical Boss has been defeated. An Eclipse has a chance of occurring at any given dawn.");
        add("bestiary.confluence.filter.rain.title", "Rain");
        add("bestiary.confluence.filter.rain.desc", "Rain is an event that affects all surface biomes for its duration.");
        add("bestiary.confluence.filter.windy_day.title", "Windy Day");
        add("bestiary.confluence.filter.windy_day.desc", "A Windy Day is an event that occurs when the wind speed exceeds 20 mph.");
        add("bestiary.confluence.filter.blizzard.title", "Blizzard");
        add("bestiary.confluence.filter.blizzard.desc", "When in a Snow biome during Rain, it will manifest as a Blizzard, causing increased snowfall.");
        add("bestiary.confluence.filter.sandstorm.title", "Sandstorm");
        add("bestiary.confluence.filter.sandstorm.desc", "A Sandstorm is an event exclusive to Deserts that occurs in all Deserts simultaneously.");
        add("bestiary.confluence.filter.meteor.title", "Meteor");
        add("bestiary.confluence.filter.meteor.desc", "The Meteor biome is a mini-biome that forms when a meteorite crashes into the world.");
        add("bestiary.confluence.filter.halloween.title", "Halloween");
        add("bestiary.confluence.filter.halloween.desc", "Halloween is a seasonal event that runs from mid-October to early November.");
        add("bestiary.confluence.filter.christmas.title", "Christmas");
        add("bestiary.confluence.filter.christmas.desc", "Christmas is a seasonal event that starts in mid-December and ends in early January.");
        add("bestiary.confluence.filter.party.title", "Party");
        add("bestiary.confluence.filter.party.desc", "A Party is an event that can occur randomly or be manually activated with a Party Center.");
        add("bestiary.confluence.filter.goblin_invasion.title", "Goblin Invasion");
        add("bestiary.confluence.filter.goblin_invasion.desc", "The Goblin Army (also known as the Goblin Invasion) is an invasion event that causes unique Goblin enemies to spawn instead of regular enemies.");
        add("bestiary.confluence.filter.pirate_invasion.title", "Pirate Invasion");
        add("bestiary.confluence.filter.pirate_invasion.desc", "The Pirate Invasion is a Hardmode invasion event that causes pirate-themed enemies to spawn instead of regular enemies.");
        add("bestiary.confluence.filter.pumpkin_moon.title", "Pumpkin Moon");
        add("bestiary.confluence.filter.pumpkin_moon.desc", "The Pumpkin Moon is a Hardmode, post-Plantera event with a Halloween theme.");
        add("bestiary.confluence.filter.frost_moon.title", "Frost Moon");
        add("bestiary.confluence.filter.frost_moon.desc", "The Frost Moon is a Hardmode, post-Plantera event with a Christmas theme.");
        add("bestiary.confluence.filter.martian_madness.title", "Martian Madness");
        add("bestiary.confluence.filter.martian_madness.desc", "Martian Madness is a Hardmode, post-Golem invasion event that causes unique alien-themed enemies to spawn instead of regular enemies.");
        add("bestiary.confluence.filter.frost_legion.title", "Frost Legion");
        add("bestiary.confluence.filter.frost_legion.desc", "The Frost Legion is a Hardmode invasion event that causes unique snowman enemies to spawn instead of regular enemies.");
        add("bestiary.confluence.filter.old_ones_army.title", "Old One's Army");
        add("bestiary.confluence.filter.old_ones_army.desc", "The Old One's Army is a unique Dungeon Defenders 2 crossover event.");
        add("bestiary.confluence.filter.solar_pillar.title", "Solar Pillar");
        add("bestiary.confluence.filter.solar_pillar.desc", "The Solar Pillar is a melee-themed Celestial Pillar.");
        add("bestiary.confluence.filter.vortex_pillar.title", "Vortex Pillar");
        add("bestiary.confluence.filter.vortex_pillar.desc", "The Vortex Pillar is a ranged-themed Celestial Pillar.");
        add("bestiary.confluence.filter.nebula_pillar.title", "Nebula Pillar");
        add("bestiary.confluence.filter.nebula_pillar.desc", "The Nebula Pillar is a magic-themed Celestial Pillar.");
        add("bestiary.confluence.filter.stardust_pillar.title", "Stardust Pillar");
        add("bestiary.confluence.filter.stardust_pillar.desc", "The Stardust Pillar is a summoner-themed Celestial Pillar.");
        add("bestiary.confluence.filter.if_unlocked.title", "If Unlocked");
        add("bestiary.confluence.filter.if_unlocked.desc", "If Unlocked");
        add("bestiary.confluence.filter.boss_enemy.title", "Boss Enemy");
        add("bestiary.confluence.filter.boss_enemy.desc", "Bosses are aggressive and resilient enemies that pose a significant challenge to the player.");
        add("bestiary.confluence.filter.rare_creature.title", "Rare Creature");
        add("bestiary.confluence.filter.rare_creature.desc", "This creature is very rare.");

        add("bestiary.entity.terra_entity.guide.desc", "The Guide always offers useful advice and crafting recipes. His origins and unusual connections to this world remain a mystery.");
        add("bestiary.entity.terra_entity.merchant.desc", "The Merchant acts as a simple general store of sorts, providing useful starter tools and supplies needed for exploration.");
        add("bestiary.entity.terra_entity.nurse.desc", "The Nurse's snarky attitude and poor bedside manner may be scary, but for a price, she will cure all that ails a wounded Terrarian.");
        add("bestiary.entity.terra_entity.demolitionist.desc", "Tread carefully around this dwarf. The Demolitionist is an explosive fanatic and sells dangerous things that go 'Boom!'");
        add("bestiary.entity.terra_entity.angler.desc", "The Angler, a rude fishing genius, sends others to find weird, rare fish. He rewards random items, entertained by any misfortunes.");
        add("bestiary.entity.terra_entity.dryad.desc", "The Dryad is the last of her kind. She is connected with nature and can analyze its purity worldwide. She sells seeds, too!");
        add("bestiary.entity.terra_entity.arms_dealer.desc", "The Arms Dealer has everything anyone could need to shoot things dead, from little round bullets to guns made from sharks.");
        add("bestiary.entity.terra_entity.dye_trader.desc", "Eccentric and rather snobby to a fault, the Dye Trader has expensive tastes. He is passionate about the materials used in the dyes he sells.");
        add("bestiary.entity.terra_entity.painter.desc", "The Painter can talk about all the different shades of colors with which one can paint the walls. He'll sell but a handful of them!");
//        add("bestiary.entity.terra_entity.stylist.desc", "The Stylist loves style, gossip, and hair. Aside from performing a miracle makeover, she sells some hair product as well.");
        add("bestiary.entity.terra_entity.zoologist.desc", "The Zoologist, resident lycanthrope, adores animals. Her fox-like biology resulted from a cursed animal bite.");
//        add("bestiary.entity.terra_entity.tavernkeep.desc", "The Tavern Keep once managed a bar in another universe. He's here to help stop the Old One's Army from conquering this world.");
//        add("bestiary.entity.terra_entity.golfer.desc", "The Golfer is a wise, middle-aged man who sells all sorts of golfing equipment. He's got game and knows how to score.");
        add("bestiary.entity.terra_entity.goblin_tinkerer.desc", "Exiled from the rest of goblinkind for being an intelligent pacifist, the Tinkerer sells tools for combining accessories into stronger versions.");
        add("bestiary.entity.terra_entity.witch_doctor.desc", "It's unusual for a Lihzahrd to be outside the Temple. Even more unusual are the voodoo things he sells. He prefers his jungle digs.");
        add("bestiary.entity.terra_entity.mechanic.desc", "The Mechanic was imprisoned for her aptitude in engineering. She sells wiring and tools for putting together anything imaginable.");
        add("bestiary.entity.terra_entity.clothier.desc", "Once trapped under a curse, the Clothier is the master of thread. If it's fashion that's desired, he's the man! He talks in a familiar way.");
//        add("bestiary.entity.terra_entity.wizard.desc", "The Wizard is an absent-minded, demented old man who dabbles in the arcane arts. He sells magical trinkets to train new apprentices.");
