        add("bestiary.entity.terra_entity.gray_cockatiel.desc", "A very social animal by nature, these close cousins of parrots can often be taught to say simple phrases.");
        add("bestiary.entity.terra_entity.gold_bird.desc", "Rarely, critters are found coated entirely in gold! Shopkeepers will pay handsomely for these, or you can show them off in cages!");
        add("bestiary.entity.terra_entity.goldfish.desc", "A seemingly ordinary goldfish, until it decides to rain.");
        add("bestiary.entity.terra_entity.gold_goldfish.desc", "Rarely, critters are found coated entirely in gold! Shopkeepers will pay handsomely for these, or you can show them off in cages!");
        add("bestiary.entity.terra_entity.squirrel.0.desc", "Fast moving and erratic woodland creatures with grayish-brown fur. Got nuts?");
        add("bestiary.entity.terra_entity.squirrel.1.desc", "Rare, red-furred hyperactive rodents which scurry about the woods.");
        add("bestiary.entity.terra_entity.jewel_squirrel.1.desc", "Rarely, critters are found coated entirely in gold! Shopkeepers will pay handsomely for these, or you can show them off in cages!");
        add("bestiary.entity.terra_entity.mouse.desc", "Mice squeak around harmlessly, looking for small insects in damp underground locations.");
