        add("bestiary.entity.terra_entity.rat.desc", "These fuzzy rodents sniff about in putrid locations scavenging for food. They are avoided in fear of diseases they may carry.");
        add("bestiary.entity.terra_entity.maggot.desc", "An unsavory larval bug which feasts on dead, rotting matter. Fish are somewhat attracted to these.");
        add("bestiary.entity.terra_entity.jewel_squirrel.2.desc", "Glistening squirrels who strayed too deep become ensorcelled with residual cursed energy retained in gemstones.");
