        add("bestiary.entity.terra_entity.scorpion.desc", "Harmlessly scuttles around the desert looking for food. Fish are barely attracted to these.");
        add("bestiary.entity.terra_entity.black_scorpion.desc", "Despite its menacing appearance, it is quite docile unless threatened or facing smaller prey. Fish are occasionally attracted to these.");
//        add("bestiary.entity.terra_entity.grebe.desc", "An exotic waterfowl that thrives in the desert oasis.");
//        add("bestiary.entity.terra_entity.pupfish.desc", "These fish prefer isolated, extreme climates where competition is scarce, such as the lakebeds of a desert oasis.");
