        add("bestiary.entity.terra_entity.sea_turtle.desc", "A soft-shelled reptile that prefers saltwater and marine prey.");
        add("bestiary.entity.terra_entity.dolphin.desc", "A playful sea mammal whose intelligence rivals that of humanity.");
//        add("bestiary.entity.terra_entity.jungle_turtle.desc", "Their hard shells camouflage them from vicious predators by blending in with the thick, jungly environment in which they reside.");
        add("bestiary.entity.terra_entity.grubby.desc", "Slimy, yet satisfying! Fish are somewhat attracted to these.");
        add("bestiary.entity.terra_entity.sluggy.desc", "Slow and covered in a slick mucus. Fish are especially attracted to these.");
//        add("bestiary.entity.terra_entity.buggy.desc", "A vibrant beetle-like bug. Fish are extremely attracted to these.");
//        add("bestiary.entity.terra_entity.lavafly.desc", "A variation of firefly which adapted to the intense conditions of the world's infernal core. It mimics sparking embers.");
        add("bestiary.entity.terra_entity.hell_butterfly.desc", "A solemn butterfly seeking blooms rooted in hell. Its wings glimmer with fiery veins.");
        add("bestiary.entity.terra_entity.magma_snail.desc", "A unique species of snail which withstands extreme heat. Its boiling slime trail melts down most weaker surfaces.");
//        add("bestiary.entity.terra_entity.lightning_bug.desc", "Appears at night in blessed locations, filling the sky with flashing cyan light. Fish are especially attracted to these.");
        add("bestiary.entity.terra_entity.prismatic_lacewing.desc", "Should one of these luminescent beings perish in the chaos of night, a sleeping tyrant is rumored to violently awaken.");
        add("bestiary.entity.terra_entity.glowing_snail.desc", "A snail that has mutated to adapt to the glowing mushroom environment. Fish are significantly attracted to these.");
//        add("bestiary.entity.terra_entity.gnome.desc", "A tiny long-bearded sneak who resides in oversized trees. Becomes a lawn ornament when exposed to sunlight.");
        add("bestiary.entity.terra_entity.goblin_scout.desc", "The Goblin Army sends lone soldiers out from the beaches to seek out colonies to conquer. They give warning with a tattered sigil.");
        add("bestiary.entity.terra_entity.green_slime.desc", "A simple, gelatinous creature that swallows anything and everything whole! It takes a long time to digest anything.");
        add("bestiary.entity.terra_entity.blue_slime.desc", "A simple, gelatinous creature that swallows anything and everything whole! It takes a long time to digest anything.");
        add("bestiary.entity.terra_entity.purple_slime.desc", "A simple, gelatinous creature that swallows anything and everything whole! It takes a long time to digest anything.");
        add("bestiary.entity.terra_entity.pinky.desc", "The smallest slime ever recorded, their extreme cellular density makes them incredibly durable for their small size. They eat money.");
//        add("bestiary.entity.terra_entity.windy_balloon.desc", "Some enterprising slimes ride wind currents with balloons in an effort to find food. Pop their balloons to bring them back down to earth.");
//        add("bestiary.entity.terra_entity.angry_dandelion.desc", "All this wind can make just about anyone angry. Evidently, this includes otherwise harmless dandelions and their deadly seeds.");
//        add("bestiary.entity.terra_entity.umbrella_slime.desc", "The previous owner of this umbrella learned the hard way: umbrellas are good protection against rain, but not against slime.");
        add("bestiary.entity.terra_entity.flying_fish.desc", "Certain species of fish gain the most peculiar abilities when it rains. They only like one thing about land-dwellers: their flesh.");
//        add("bestiary.entity.terra_entity.angry_nimbus.desc", "When severe storms roll through, it is said that the skies are angry. This cloud in particular is especially livid!");
        add("bestiary.entity.terra_entity.demon_eye_dilated.desc", "That suspicious feeling of being watched may very well come true in the dark of night, when Cthulhu's minions roam the skies.");
        add("bestiary.entity.terra_entity.demon_eye_sleepy.desc", "That suspicious feeling of being watched may very well come true in the dark of night, when Cthulhu's minions roam the skies.");
