        add("bestiary.entity.terra_entity.undead_viking.desc", "Long before there were pirates, stories tell of powerful vikings who raged the seas. Their remains roam the icy caverns below.");
        add("bestiary.entity.terra_entity.snow_flinx.desc", "A strange, round furry mammal with an unusually large, protruding nose. They are extremely lightweight.");
