        add("bestiary.entity.terra_entity.hellbat.desc", "What's worse than a rabid, fast-flying, and annoying flying rodent? One that is on fire, of course!");
        add("bestiary.entity.terra_entity.demon.desc", "Demons are the infantry of the underworld. Unlike their lesser brothers, they cast shadow magic rather than hell magic.");
        add("bestiary.entity.terra_entity.voodoo_demon.desc", "Higher ranking demons can possess a voodoo doll of the chosen one, whose soul is linked with the world's guardian himself.");
        add("bestiary.entity.terra_entity.lava_bat.desc", "What's worse than a rabid, fast-flying, and annoying flying rodent? One that is on fire, of course!");
