        add("bestiary.entity.terra_entity.eye_of_cthulhu.desc", "A piece of Cthulhu ripped from his body centuries ago in a bloody war. It wanders the night seeking its host body... and revenge!");
        add("bestiary.entity.terra_entity.servant_of_cthulhu.desc", "Young Demon Eyes newly birthed from the Eye of Cthulhu, brought forth to protect their master by any means necessary.");
        add("bestiary.entity.terra_entity.king_slime.desc", "Slimes normally aren't intelligent, but occasionally they merge together to become a powerful force to swallow all things.");
        add("bestiary.entity.terra_entity.eater_of_worlds.desc", "Conceived from the bottomless malice of the Corruption, this mighty abyssal worm tunnels wildly to devour all in its path.");
        add("bestiary.entity.terra_entity.brain_of_cthulhu.desc", "A piece of Cthulhu torn asunder, this vile mastermind pulses with agony and aids the Crimson in an attempt to avenge its master.");
        add("bestiary.entity.terra_entity.visual_neuron.desc", "Manipulated through the hive mind of the Crimson, Visual Neuron serve as the brain's eyes and orbit around it for defense in numbers.");
        add("bestiary.entity.terra_entity.skeletron.desc", "The disembodied bones of a former tyrant pulsed with a hatred so strong, it left behind a mighty curse which guards the Dungeon.");
        add("bestiary.entity.terra_entity.queen_bee.desc", "This highly aggressive monstrosity responds violently when her larva is disturbed; the honey-laden hives are her home turf.");
        add("bestiary.entity.terra_entity.wall_of_flesh.desc", "Serving as the world's core and guardian, the towering demon lord exists to keep powerful ancient spirits sealed away.");
        add("bestiary.entity.terra_entity.leech.desc", "A worm-like parasite spit forth from the Wall of Flesh, filled with the lifeblood of its host. This blood has healing properties.");
        add("bestiary.entity.terra_entity.the_hungry_attached.desc", "The Wall of Flesh's many mouths, attached by bloody veins. As a last resort, they can tear away and hungrily chase down threats.");
        add("bestiary.entity.terra_entity.the_hungry_flying.desc", "The Wall of Flesh's many mouths, attached by bloody veins. As a last resort, they can tear away and hungrily chase down threats.");
